var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"말해.","JPN":"言いなさい。","ENG":"Tell me.","TWN":"說吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"자크는 어디에 숨어있지?","JPN":"ジャックはどこに隠れてるの？","ENG":"Where is Jacques hiding?","TWN":"札克躲在哪裡？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"큭큭... 숨긴 누가 숨어. 우리 혁명군이 너희 같은 겁쟁이인 줄 아냐?","JPN":"ククッ……隠れる必要がどこにある？　我が革命軍はてめえらみたいな弱虫じゃないんだぜ？","ENG":"Heh heh... Hiding? Who said anything about hiding? Do you think our Resistance is full of cowards like you?","TWN":"呵呵……誰躲起來了啊？你以為我們革命軍會怕你們這種懦夫嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"보안국의 개 주제에 감히 그 이름을 함부로 담지 마시지.","JPN":"保安局の犬が、軽々しくあの人の名を呼ばないでほしいね。","ENG":"Watch your mouth. A dog of the National Security shouldn't dare speak that name so lightly.","TWN":"你這安全局的走狗，竟敢隨便提起那個名字？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"뭐?","JPN":"何だよ？","ENG":"What?","TWN":"怎樣？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"순혈지식 연대의 테오도르 팔머.","JPN":"純血知識連帯のテオドール・パルマー。","ENG":"Theodor Palmer of the Pure Blood Regiment.","TWN":"純血知識年代的西奧多．帕默。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"건국기념전당 폭발 사건에, 너 역시 가담했었지.","JPN":"建国記念館の爆発事件に加担していたよね。","ENG":"You were involved in the bombing at the National Foundation Hall as well.","TWN":"你也參與了建國紀念堂爆炸案吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"건국기념전당?","JPN":"建国記念館？","ENG":"The National Foundation Hall?","TWN":"建國紀念堂？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"그러고 보니 그 얼굴... 설마 그 여자의?","JPN":"その顔……まさか、あの女の？","ENG":"Now that I look at you... That face... Don't tell me you're that woman's–?","TWN":"這麼說來你那張臉……難道是那女人的女兒？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"판단이 빠르네. 그럼 내가 널 어떻게 할 지도 알고 있으려나?","JPN":"勘が鋭いじゃない。じゃあ、私がどうするつもりかも分かる？","ENG":"Quick on the uptake. Then you must know what I'm going to do to you, right?","TWN":"判斷還真快呢。那你應該也知道我會怎麼對付你吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"어처구니가 없군.","JPN":"ふざけやがって。","ENG":"How absurd.","TWN":"真荒謬。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"날 납치한다고 뭐가 해결되는데?","JPN":"俺を拉致したところで何が解決するっていうんだ？","ENG":"What does kidnapping me solve?","TWN":"綁架我能解決什麼問題？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"<color=#ffd34c>루이제 슈나이더는 자신의 안전을 위해 반군들과 협력하고 있었다.</color>","JPN":"<color=#ffd34c>ルイーゼ・シュナイダーは自分の身の安全のため、反乱軍に協力していた。</color>","ENG":"<color=#ffd34c>Louise Schneider had been cooperating with the rebels for the sake of her own safety.</color>","TWN":"<color=#ffd34c>露易絲．修奈德為了自身安全，曾與反抗軍合作。</color>"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"군중의 질책을 피하려고 던진 네 거짓 선동이 한 사람의 인생을 통째로 망가트렸어.","JPN":"群衆から非難されないためにばら撒いた偽の扇動で、一人の人の人生すべてを滅茶苦茶にした。","ENG":"The lie you spread to escape the public's condemnation ruined an innocent person's entire life.","TWN":"你為了躲避群眾責難而散布的謊言，毀了一個人的人生。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"...그건 필요한 희생이었다.","JPN":"……その犠牲は必要なものだったんだ。","ENG":"...It was a necessary sacrifice.","TWN":"……那是必要的犧牲。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"그 여자 하나 때문에 민중의 지지를 받는 혁명군 전체의 이미지가 실추되어선 안 됐으니까.","JPN":"あの女一人のために、民衆から支持を集めている革命軍全体のイメージを汚すわけにはいかなかったからな。","ENG":"The entire Resistance couldn't afford to lose the people's support because of one woman.","TWN":"整個革命軍的形象不能因為那個女人而失去民眾的支持。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"네가 정부에 충성하는 개라면 작은 희생이 필요하단 것쯤은 누구보다 잘 이해하고 있겠지.","JPN":"お前が政府に忠誠を誓っている犬なら、小さな犠牲が必要なことくらい誰よりも理解してるはずだろう？","ENG":"If you're the government's loyal hound, you should understand better than anyone that small sacrifices are sometimes necessary.","TWN":"如果你是忠於政府的走狗，那麼你一定比誰都明白，小小的犧牲是必須的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"너흰 스스로를 애국자라 생각하지.","JPN":"君たちは自らを愛国者だと思ってるんだろうね。","ENG":"You think of yourselves as patriots.","TWN":"你們自詡為愛國者吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"자신들이 벌인 짓 때문에 무고한 사람 수백이 휘말려도, 그걸 대의라는 숭고한 사상으로 포장하면서 말이야.","JPN":"自分たちが起こした事件のせいで何の罪もない多くの人が巻き込まれても、それを大儀という崇高な思想で美化してさ。","ENG":"Even when hundreds of innocent people are dragged into the consequences of what you've done, you dress it up as some noble cause.","TWN":"即使自己的所作所為傷害了數百個無辜的人，依舊能用崇高的理念包裝這一切。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"끄아악!!","JPN":"くはあっ！！","ENG":"Aaaagh!!","TWN":"啊啊啊！！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"자, 잠깐...!","JPN":"ま、待て……！","ENG":"W-wait...!","TWN":"等、等一下……！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"날 죽이는 건 별 의미가 없어. 너도 그 정도는 알잖아. 자크에 대한 정보가 필요한 거지?","JPN":"俺を殺しても意味がない。お前もそれくらいは分かってるはずだ。ジャックの情報が必要なんだろう？","ENG":"You know that killing me won't accomplish much. You're after information on Jacques, right?","TWN":"你不也知道殺了我沒什麼意義嗎？你需要的是札克的情報，對吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"대장을 노리는 거잖아! 안 그래? 결국 그날 일을 주도했던 건 지휘관이니까!","JPN":"隊長を狙ってるんだろう！　違うか？　結局あの日の事件を主導したのは指揮官だからな！","ENG":"You're aiming for him! Aren't you? He was the one who orchestrated what happened that day!","TWN":"你的目標不是隊長嗎？對吧？畢竟是他主導那天的事！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"걱정 마. 모두 다 대가를 치르게 될 거야.","JPN":"安心して。全員に償いはさせるから。","ENG":"Don't worry. Everyone will pay the price.","TWN":"別擔心，所有人都會付出代價。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"네가 먼저일 뿐이지.","JPN":"ただ、君が最初ってだけ。","ENG":"You're just first.","TWN":"只是從你開始而已。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그럼에도, 우리에겐 대의라는 명분이 필요해.","JPN":"だとしても、私たちには大儀という口実がいる。","ENG":"Even so, we still need a cause to justify ourselves.","TWN":"但即便如此，我們仍需要一個名目。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"그래야만, 죄의식이라는 타고난 본능으로부터 우리 스스로를 지킬 수 있으니까.","JPN":"でないと、罪の意識という持って生まれた本能から自分自身を守ることができないから。","ENG":"Otherwise, we can't protect ourselves from the instinctive guilt we're born with.","TWN":"這樣才能保護自己不被天生的罪惡感吞噬。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"살려주게... 제단의 위치부터 그 여자가 사는 곳까지, 전부 말해줬잖나.","JPN":"助けてくれ……祭壇の位置からあの女が住んでる場所まで、全部話しただろう？","ENG":"Have mercy... I told you everything. The location of the altar, even where that woman lives.","TWN":"饒了我吧……我已經把祭壇的位置、那個女人住的地方都告訴你了。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRISON_NPC_HARMONY_NULL","text":{"KOREA":"대체... 나한테 뭘 원하는 건가?","JPN":"いったい……これ以上何を聞き出そうというのだ？","ENG":"What... exactly do you want from me?","TWN":"你到底……想從我這裡得到什麼？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};